function drawSettingsScreen(dt) {
  const u = UNIT;
  ctx.fillStyle = '#0a1628'; ctx.fillRect(0, 0, W, H);
  ctx.textAlign = 'center'; ctx.textBaseline = 'middle';
  ctx.font = FONTS['b2'] || ('bold ' + Math.round(u*2) + 'px monospace');
  ctx.fillStyle = '#FFD700';
  ctx.fillText('SETTINGS', W/2, H * 0.08);

  let y = H * 0.18;
  const sliderW = W * 0.5, sliderH = u * 0.3, sliderX = W * 0.35;

  // Music Volume
  ctx.textAlign = 'left'; ctx.font = FONTS['b0.6'] || ('bold ' + Math.round(u*0.6) + 'px monospace');
  ctx.fillStyle = '#FFF';
  ctx.fillText('Music Volume', W * 0.08, y);
  fillRR(sliderX, y - sliderH/2, sliderW, sliderH, sliderH/2, 'rgba(255,255,255,0.15)', null, 0);
  fillRR(sliderX, y - sliderH/2, sliderW * musicVolume, sliderH, sliderH/2, '#4CAF50', null, 0);
  ctx.beginPath(); ctx.arc(sliderX + sliderW * musicVolume, y, u * 0.35, 0, PI2);
  ctx.fillStyle = '#FFF'; ctx.fill();
  ctx.textAlign = 'right'; ctx.fillText(Math.round(musicVolume * 100) + '%', W * 0.93, y);
  y += u * 1.5;

  // SFX Volume
  ctx.textAlign = 'left'; ctx.fillStyle = '#FFF';
  ctx.fillText('SFX Volume', W * 0.08, y);
  fillRR(sliderX, y - sliderH/2, sliderW, sliderH, sliderH/2, 'rgba(255,255,255,0.15)', null, 0);
  fillRR(sliderX, y - sliderH/2, sliderW * sfxVolume, sliderH, sliderH/2, '#2196F3', null, 0);
  ctx.beginPath(); ctx.arc(sliderX + sliderW * sfxVolume, y, u * 0.35, 0, PI2);
  ctx.fillStyle = '#FFF'; ctx.fill();
  ctx.textAlign = 'right'; ctx.fillText(Math.round(sfxVolume * 100) + '%', W * 0.93, y);
  y += u * 1.5;

  // Screen Shake toggle
  ctx.textAlign = 'left'; ctx.fillStyle = '#FFF';
  ctx.fillText('Screen Shake', W * 0.08, y);
  const shakeOn = save.screenShake !== false;
  drawButton(sliderX, y - u * 0.4, u * 3, u * 0.8, shakeOn ? 'ON' : 'OFF', {
    fill: shakeOn ? 'rgba(76,175,80,0.4)' : 'rgba(100,100,100,0.3)',
    stroke: shakeOn ? '#4CAF50' : 'rgba(150,150,150,0.4)',
    font: FONTS['b0.5'] || ('bold ' + Math.round(u*0.5) + 'px monospace'),
    textColor: shakeOn ? '#4CAF50' : 'rgba(150,150,150,0.6)'
  });
  y += u * 2;

  // Credits
  ctx.textAlign = 'center';
  ctx.font = FONTS['b0.5'] || ('bold ' + Math.round(u*0.5) + 'px monospace');
  ctx.fillStyle = 'rgba(255,215,0,0.6)';
  ctx.fillText('CREDITS', W/2, y); y += u * 0.8;
  ctx.font = FONTS['n0.4'] || (Math.round(u*0.4) + 'px monospace');
  ctx.fillStyle = 'rgba(255,255,255,0.5)';
  ctx.fillText('Game Design & Programming', W/2, y); y += u * 0.5;
  ctx.fillStyle = 'rgba(255,255,255,0.35)';
  ctx.fillText('Built with HTML5 Canvas + Expo', W/2, y); y += u * 0.7;
  // Version
  ctx.fillStyle = 'rgba(255,255,255,0.3)';
  ctx.fillText('Gronk\'s Run v1.3', W/2, y);

  // Back button
  drawButton(W/2 - u*2.5, H * 0.88, u * 5, u * 1, 'BACK', {
    fill: 'rgba(60,60,80,0.7)', stroke: 'rgba(255,255,255,0.3)',
    font: FONTS['b0.65'] || ('bold ' + Math.round(u*0.65) + 'px monospace')
  });

  // Store layout for tap handling
  G._settingsLayout = { sliderX, sliderW, sliderH, baseY: H * 0.18, spacing: u * 1.5 };
}

function handleSettingsTap() {
  const tx = inp.tapX, ty = inp.tapY, u = UNIT;
  const L = G._settingsLayout;
  if (!L) return;

  // Music slider
  if (Math.abs(ty - L.baseY) < u * 0.6 && tx >= L.sliderX - u && tx <= L.sliderX + L.sliderW + u) {
    musicVolume = clamp((tx - L.sliderX) / L.sliderW, 0, 1);
    AudioManager.updateVolumes();
    save.musicVolume = musicVolume; persistSave();
    return;
  }
  // SFX slider
  const sfxY = L.baseY + L.spacing;
  if (Math.abs(ty - sfxY) < u * 0.6 && tx >= L.sliderX - u && tx <= L.sliderX + L.sliderW + u) {
    sfxVolume = clamp((tx - L.sliderX) / L.sliderW, 0, 1);
    AudioManager.updateVolumes();
    save.sfxVolume = sfxVolume; persistSave();
    sfxUITap(); // test sound
    return;
  }
  // Screen shake toggle
  const shakeY = L.baseY + L.spacing * 2;
  if (tx >= L.sliderX && tx <= L.sliderX + u * 3 && Math.abs(ty - shakeY) < u * 0.6) {
    save.screenShake = save.screenShake === false ? true : false;
    persistSave(); sfxUITap();
    return;
  }
  // Back button
  if (tx > W/2 - u*2.5 && tx < W/2 + u*2.5 && ty > H*0.88 && ty < H*0.88 + u) {
    G.phase = G._settingsReturnPhase || 'LEVEL_MAP'; sfxUITap();
    return;
  }
}

function drawSpeakerIcon(x, y, size) {
  ctx.font = `${size}px sans-serif`;
  ctx.textAlign = 'left'; ctx.textBaseline = 'top';
  ctx.fillStyle = 'rgba(255,255,255,0.7)';
  ctx.fillText(soundMuted ? '\uD83D\uDD07' : '\uD83D\uDD0A', x, y);
}
function checkSpeakerTap(tx, ty, x, y, size) {
  return tx >= x && tx <= x + size*1.2 && ty >= y && ty <= y + size*1.2;
}

